import type { SSOLogOutputInterface, SSOLoginConfig } from '@mtfe/sso-web-oidc-base';
/**
 * Cli客户端登录配置
 */
export interface SSOCliLoginConfig extends Omit<SSOLoginConfig, 'mode' | 'sameSite'> {
    /**
     * 日志输出器，如果不指定默认控制台输出
     */
    logOutputer?: SSOLogOutputInterface;
    /**
     * 自定义业务标识，用于后续使用情况统计
     */
    tag?: string;
}
